import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenerativeAI } from "@google/generative-ai";

// 🔑 YOUR NEW KEY IS HERE
const API_KEY = "AIzaSyBA3WcmWZskhy8Wxqkz6aXTkmmgLbNLe38"; 

function ChatBot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { text: "👋 Hi! I'm the real AI CampusBot. Ask me about projects, errors, or upload limits!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking]);

  const generateResponse = async (userQuestion) => {
    try {
      const genAI = new GoogleGenerativeAI(API_KEY);
      
      // 👇 THIS IS THE FIX: We are now using "gemini-1.5-flash"
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

      const systemContext = `
        You are CampusBot, an AI assistant for "CampusCanvas".
        
        KNOWLEDGE BASE:
        - Tech Stack: React.js, Firebase, Tailwind CSS.
        - Features: Uploads, Admin Approvals, Gallery.
        - Storage: Base64 strings (max 1MB).
        
        COMMON ERRORS: 
        * "White Screen" -> React crash.
        * "Slow Load" -> Large Base64 images.
        * "Permission Denied" -> Not Admin.
        
        Keep answers short and helpful.
      `;

      const prompt = `${systemContext}\n\nUser Question: ${userQuestion}\nAnswer:`;

      const result = await model.generateContent(prompt);
      const response = await result.response;
      return response.text();
    } catch (error) {
      console.error("AI Error:", error);
      return `⚠️ Connection Error: ${error.message}`;
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    const aiText = await generateResponse(input);

    setIsThinking(false);
    setMessages((prev) => [...prev, { text: aiText, isBot: true }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">
      {isOpen && (
        <div className="bg-white w-80 h-96 rounded-2xl shadow-2xl border border-gray-200 flex flex-col overflow-hidden mb-4">
          <div className="bg-gradient-to-r from-indigo-600 to-purple-600 p-4 flex justify-between items-center text-white shadow-md">
            <div className="flex items-center gap-2">
              <div className="bg-white/20 p-1.5 rounded-full backdrop-blur-md">🤖</div>
              <div>
                <h3 className="font-bold text-sm">CampusBot AI</h3>
                <p className="text-[10px] text-indigo-100 opacity-80">Online • Gemini Flash</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 w-8 h-8 rounded-full transition">✕</button>
          </div>

          <div className="flex-1 p-4 overflow-y-auto bg-slate-50 space-y-3">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 rounded-xl text-sm leading-relaxed shadow-sm ${
                  msg.isBot ? 'bg-white border border-gray-200 text-gray-800 rounded-tl-none' : 'bg-indigo-600 text-white rounded-tr-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isThinking && <div className="p-3 text-xs text-gray-400">Thinking...</div>}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-3 border-t bg-white flex gap-2">
            <input 
              type="text" value={input} onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..." 
              className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button onClick={handleSend} disabled={isThinking} className="w-10 h-10 rounded-full bg-indigo-600 text-white flex items-center justify-center">➤</button>
          </div>
        </div>
      )}
      {!isOpen && (
        <button onClick={() => setIsOpen(true)} className="w-16 h-16 bg-gradient-to-tr from-indigo-600 to-purple-600 text-white rounded-full shadow-xl flex items-center justify-center text-3xl transition-all hover:scale-110">✨</button>
      )}
    </div>
  );
}

export default ChatBot;
